const DREAMCATCHER_IMG = "data:image/png;base64,";

function DreamCatcher({ size = 120 }) {
  return (
    <img
      src={DREAMCATCHER_IMG}
      width={size * 1.8}
      height={size * 1.8}
      style={{objectFit:"contain",mixBlendMode:"screen",filter:"drop-shadow(0 0 30px rgba(168,85,247,0.6))"}}
    />
  );
}

function Stars() {
  const pts = Array.from({length:0},(_,i)=>({
    x:Math.random()*100, y:Math.random()*100,
    s:Math.random()*2.4+0.6, o:Math.random()*0.6+0.2,
    d:Math.random()*4, c:["#fcd34d","#a7f3e8","#f9c5e8","#c9b8f7","#ffffff"][Math.floor(Math.random()*5)]
  }));
  return (
    <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:0}}>
      <style>{`
        @keyframes tw { 0%, 100% { opacity: .2 } 50% { opacity: .9 } }
        @keyframes spin { from { transform: rotate(0) } to { transform: rotate(360deg) } }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(12px) } to { opacity: 1; transform: translateY(0) } }
        @keyframes pulse { 0%, 100% { transform: scale(1) } 50% { transform: scale(1.04) } }
        @keyframes slideIn { from { transform: translateX(100%) } to { transform: translateX(0) } }
        .prisma-card { position: relative; }
        .prisma-card::before { content:""; position:absolute; inset:0; border-radius:inherit; padding:2px; background:linear-gradient(145deg,#ff2bd4,#b06bff,#2f6bff,#00e8d0,#15e85f); -webkit-mask:linear-gradient(#fff 0 0) content-box,linear-gradient(#fff 0 0); -webkit-mask-composite:xor; mask-composite:exclude; pointer-events:none; }
      `}</style>
      {pts.map((p,i)=>(
        <div key={i} style={{
          position:"absolute",left:`${p.x}%`,top:`${p.y}%`,
          width:p.s,height:p.s,borderRadius:"50%",background:p.c,
          opacity:p.o,animation:`tw ${2+p.d}s ease-in-out infinite`,
          animationDelay:`${p.d}s`
        }}/>
      ))}
    </div>
  );
}

function Btn({children, onClick, style={}, disabled=false}) {
  return (
    <button onClick={onClick} disabled={disabled} style={{
      border:"none",cursor:disabled?"not-allowed":"pointer",
      fontFamily:S.fontUI,transition:"opacity .15s",
      opacity:disabled?.5:1,...style
    }}>{children}</button>
  );
}

function Card({children, style={}}) {
  return (
    <div className="prisma-card" style={{
      background:C.card,position:"relative",
      borderRadius:16,padding:"16px",...style
    }}>{children}</div>
  );
}

function Spinner() {
  return (
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:10,padding:28}}>
      <div style={{width:32,height:32,border:`3px solid ${C.border}`,borderTop:`3px solid ${C.gold}`,borderRadius:"50%",animation:"spin 1s linear infinite"}}/>
      <span style={{color:C.muted,fontSize:13,fontFamily:S.fontUI}}>Generando tu mensaje...</span>
    </div>
  );
}

function hoyES(){
  return new Date().toLocaleDateString("en-CA");
}

function diasDesde(fechaStr){
  try{ var a=new Date(fechaStr+"T00:00:00"); var b=new Date(hoyES()+"T00:00:00"); return Math.floor((b-a)/86400000); }catch(e){ return 0; }
}

async function askClaude(prompt) {
  var _filtroTotal = "\n\nREGLAS ESTRICTAS Y OBLIGATORIAS, NUNCA las cruces: (1) NO menciones a Dios, ninguna religión ni términos religiosos (Dios, Señor, divino, rezar, oración, fe, iglesia, Biblia, Jesús, Alá, espíritu santo, etc.). (2) NO menciones política, partidos, gobiernos ni temas polémicos. (3) NO incluyas contenido sexual ni insinuaciones sexuales. (4) NO uses groserías, vulgaridades ni lenguaje obsceno. Mantén SIEMPRE un tono de bienestar y espiritualidad universal y secular (el universo, la energía, tu interior, tu fuerza, la calma, la naturaleza, la vida), apropiado y respetuoso para todo público.";
  prompt = prompt + _filtroTotal;
  const res = await fetch("/api/claude",{
    method:"POST",
    headers:{"Content-Type":"application/json"},
    body:JSON.stringify({
      model:"claude-sonnet-4-6",
      max_tokens:1000,
      messages:[{role:"user",content:prompt}]
    })
  });
  const d = await res.json();
  if(d.content?.[0]) return d.content[0].text;
  throw new Error("Sin respuesta");
}

