function Setup({onDone}) {
  const [name, setName] = useState("");
  const [gender, setGender] = useState("");
  const [birthday, setBirthday] = useState("");
  const [bMonth, setBMonth] = useState("");
  const [bDay, setBDay] = useState("");
  const ok = name.trim() && gender;

  return (
    <div style={{
      minHeight:"100vh",display:"flex",flexDirection:"column",
      alignItems:"center",justifyContent:"center",
      padding:"24px 20px",position:"relative",zIndex:1
    }}>
      <div style={{margin:"20px 0",animation:"pulse 3s ease-in-out infinite"}}>
        <DreamCatcher size={140}/>
      </div>
      <h2 style={{
        color:C.gold,fontSize:24,fontWeight:800,fontFamily:S.fontFamily,
        textAlign:"center",margin:"12px 0 4px"
      }}>¿Cómo Te Llamas?</h2>
      <p style={{color:C.muted,fontSize:14,fontFamily:S.fontUI,margin:"0 0 24px",textAlign:"center"}}>
        Para Personalizar Tu Experiencia
      </p>

      <input
        value={name} onChange={e=>setName(e.target.value)}
        placeholder="Tu nombre..."
        style={{
          width:"100%",maxWidth:340,background:C.cardDark,
          border:`1px solid ${C.border}`,borderRadius:12,
          padding:"16px 18px",color:C.goldL,fontSize:17,
          fontFamily:S.fontUI,outline:"none",boxSizing:"border-box",marginBottom:24
        }}
      />

      <p style={{
        color:C.gold,fontSize:16,fontWeight:700,fontFamily:S.fontUI,
        margin:"0 0 14px",textAlign:"center"
      }}>¿Cómo Te Identificas?</p>

      <div style={{display:"flex",gap:10,marginBottom:32,flexWrap:"wrap",justifyContent:"center"}}>
        {[["👩","Mujer"],["👨","Hombre"],["⭐","Prefiero No Decir"]].map(([e,g])=>(
          <Btn key={g} onClick={()=>setGender(g)} style={{
            padding:"14px 16px",borderRadius:14,fontSize:13,
            fontFamily:S.fontUI,fontWeight:600,
            background: gender===g ? `${C.purple}55` : C.cardDark,
            border: `2px solid ${gender===g ? C.purpleL : C.border}`,
            color: C.text,display:"flex",flexDirection:"column",
            alignItems:"center",gap:4,minWidth:90
          }}>
            <span style={{fontSize:24}}>{e}</span>{g}
          </Btn>
        ))}
      </div>

      <p style={{color:C.muted,fontSize:13,fontFamily:S.fontUI,margin:"0 0 10px",textAlign:"center"}}>🎂 ¿Cuándo es tu cumpleaños? (opcional)</p>
      <div style={{display:"flex",gap:10,width:"100%",maxWidth:340,marginBottom:28}}>
        <select value={bMonth} onChange={e=>{const m=e.target.value;setBMonth(m);setBirthday(m&&bDay?"0000-"+m+"-"+bDay:"");}}
          style={{flex:2,background:C.cardDark,border:"1px solid "+C.border,borderRadius:12,padding:"16px 14px",color:bMonth?C.goldL:C.muted,fontSize:16,fontFamily:S.fontUI,outline:"none",boxSizing:"border-box"}}>
          <option value="">Mes</option>
          {[["01","Enero"],["02","Febrero"],["03","Marzo"],["04","Abril"],["05","Mayo"],["06","Junio"],["07","Julio"],["08","Agosto"],["09","Septiembre"],["10","Octubre"],["11","Noviembre"],["12","Diciembre"]].map(([v,l])=>(
            <option key={v} value={v}>{l}</option>
          ))}
        </select>
        <select value={bDay} onChange={e=>{const d=e.target.value;setBDay(d);setBirthday(bMonth&&d?"0000-"+bMonth+"-"+d:"");}}
          style={{flex:1,background:C.cardDark,border:"1px solid "+C.border,borderRadius:12,padding:"16px 14px",color:bDay?C.goldL:C.muted,fontSize:16,fontFamily:S.fontUI,outline:"none",boxSizing:"border-box"}}>
          <option value="">Día</option>
          {Array.from({length:31},(_,i)=>String(i+1).padStart(2,"0")).map(d=>(
            <option key={d} value={d}>{parseInt(d,10)}</option>
          ))}
        </select>
      </div>

      <Btn onClick={()=>ok&&onDone({name:name.trim(),gender,birthday})} disabled={!ok} style={{
        width:"100%",maxWidth:340,padding:"18px",borderRadius:14,
        background: ok ? `linear-gradient(135deg,${C.gold},${C.goldL})` : C.border,
        color: ok ? "#1a0a00" : C.muted,
        fontSize:17,fontWeight:800,fontFamily:S.fontUI,letterSpacing:.5
      }}>
        {name ? `Comenzar, ${name.split(" ")[0]} ✨` : "Comenzar ✨"}
      </Btn>
    </div>
  );
}

function genderHint(g){
  var x=(g||"").toLowerCase();
  if(x!=="mujer" && x!=="hombre") return "NO asumas ni especifiques el g\u00e9nero de la persona; usa SIEMPRE lenguaje neutral e inclusivo, evitando 'hombre', 'mujer' y adjetivos con g\u00e9nero marcado.";
  var fem = x==="mujer";
  if(Math.random() < 0.10) return "La persona se identifica como " + (fem?"mujer":"hombre") + "; en ESTA frase puedes usar con sutileza lenguaje en " + (fem?"femenino":"masculino") + " si fluye natural.";
  return "Usa lenguaje NEUTRAL en g\u00e9nero en esta frase (aunque la persona se identifique como " + (fem?"mujer":"hombre") + "), sin marcar 'hombre' ni 'mujer'.";
}

async function shareQuote(quote, bg) {
  try {
    var cv = document.createElement("canvas"); cv.width=1080; cv.height=1080;
    var x = cv.getContext("2d");
    var TH=[["#1e0a4e","#0d0d2b","#06061a","#fde68a","#a78bfa"],["#0f2027","#203a43","#2c5364","#e0f7fa","#80deea"],["#42275a","#734b6d","#bc4e9c","#ffe9f5","#ffd6a5"],["#05010f","#0b132b","#1c2541","#ffffff","#9db4ff"],["#3a1c71","#d76d77","#ffaf7b","#fff8f0","#ffe9c7"],["#134e5e","#2c7a6b","#71b280","#eafff5","#cdeede"]]; var CTH={canva:["#2a8a8c","#3848b0","#5a28b0","#ffffff","#fde68a"],turquesa:["#1aa39a","#0e5e5a","#06262e","#c8fff5","#7fe8dd"],rojo:["#c22b2b","#7a1818","#2a0808","#ffd0d0","#ff9c9c"],verde:["#1f9c47","#125e2c","#06260f","#cfffd9","#8fe6a3"],azulroyal:["#2f4fc2","#1c2f7a","#08122e","#d0d9ff","#9db4ff"],mostaza:["#b0860f","#6e520a","#241b06","#ffeec0","#f0d27a"],negro:["#2e2e2e","#161616","#000000","#e8e8e8","#b0b0b0"],vturquesa:["#0aa89a","#066058","#04231f","#c8fff5","#7fffe8"],vrojo:["#d42424","#841414","#2a0606","#ffd0d0","#ff9090"],vverde:["#12b04a","#0a6e2e","#04220f","#d0ffdd","#80f0a0"],vazulroyal:["#2f57d4","#1a338c","#06112e","#d0ddff","#90b4ff"],vmostaza:["#c2900f","#7a5c08","#2a1f04","#fff0c0","#ffdc80"],vnegro:["#2e2e38","#161618","#000000","#e8e8f0","#b0b0c0"],fucsia:["#d41a82","#84104e","#2a0518","#ffd0ec","#ff90d0"],lila:["#8a4fd4","#542a84","#1c0a33","#ecd0ff","#cba3ff"],prisma:["#ff2bd4","#7c3aed","#1a1448","#ffffff","#ffd6f5"],vcoral:["#d44a3a","#842818","#2a0c06","#ffd6c8","#ff9c80"],anaranjado:["#d46500","#843e00","#2a1300","#ffe0c0","#ffb060"],azulcielo:["#1a90c2","#0c5a7a","#04202e","#c8ecff","#80d0ff"],gris:["#5a5f68","#34373d","#15171c","#eaecef","#c0c4cc"],plateado:["#8a8f99","#54585f","#26282e","#f5f6f8","#d2d6de"],dorado:["#c29a0f","#7a600a","#2a1f04","#fff2c8","#ffe080"],verdelima:["#6e9c00","#456000","#1a2600","#eaffc0","#c8f060"],burgundy:["#9c1038","#620a24","#1f0410","#ffccd8","#f08ca0"],magenta:["#d41aac","#84126e","#2a0524","#ffd0f4","#ff90e0"]}; var th=CTH[bg]||CTH.canva; var g = x.createLinearGradient(0,0,0,1080); g.addColorStop(0,th[0]); g.addColorStop(0.5,th[1]); g.addColorStop(1,th[2]);
    x.fillStyle=g; x.fillRect(0,0,1080,1080);
    x.fillStyle="#ffffff"; for(var i=0;i<70;i++){ x.globalAlpha=Math.random()*0.6+0.2; x.beginPath(); x.arc(Math.random()*1080,Math.random()*1080,Math.random()*2+0.5,0,7); x.fill(); } x.globalAlpha=1;
    x.fillStyle=th[3]; x.textAlign="center"; x.textBaseline="middle"; x.font="italic 84px Georgia";
    var full = "\u201C"+(quote||"")+"\u201D"; var words=full.split(" "); var lines=[]; var ln="";
    for(var w=0;w<words.length;w++){ var tt=ln?ln+" "+words[w]:words[w]; if(x.measureText(tt).width>880 && ln){ lines.push(ln); ln=words[w]; } else { ln=tt; } } if(ln) lines.push(ln);
    var lh=116; var sy=470-(lines.length-1)*lh/2; for(var L=0;L<lines.length;L++){ x.fillText(lines[L],540,sy+L*lh); }
    x.strokeStyle=th[4]; x.lineWidth=4; x.beginPath(); x.moveTo(490,874); x.lineTo(590,874); x.stroke(); x.shadowColor="rgba(40,15,5,0.55)"; x.shadowBlur=12; x.shadowOffsetX=0; x.shadowOffsetY=3; x.fillStyle="#ffffff"; x.font="700 62px system-ui"; x.fillText("\u2728 Atrapa Sue\u00F1os \u2728",540,932);
    x.fillStyle=th[4]; x.font="600 28px system-ui"; x.fillText("INSPIRACI\u00D3N \u00B7 MOTIVACI\u00D3N \u00B7 AFIRMACI\u00D3N",540,994); x.shadowColor="transparent"; x.shadowBlur=0; x.shadowOffsetY=0;
    cv.toBlob(async function(b){ try { var f=new File([b],"atrapa-suenos.png",{type:"image/png"}); if(navigator.canShare && navigator.canShare({files:[f]})){ await navigator.share({files:[f],title:"Atrapa Sue\u00F1os"}); } else { var u=URL.createObjectURL(b); var a=document.createElement("a"); a.href=u; a.download="atrapa-suenos.png"; a.click(); URL.revokeObjectURL(u); } } catch(e){} },"image/png");
  } catch(e){}
}

function MsgCard({icon, label, quote, cont, onClose, bg}) {
  const [expanded, setExpanded] = useState(false);
  const [liked, setLiked] = useState(false);
  const renderText = (t) => (t||"").split("\n").filter(l=>l.trim()).map((line,i)=>(
    <p key={i} style={{margin:"0 0 8px"}}>{line}</p>
  ));
  return (
    <Card style={{animation:"fadeUp .4s ease-out",marginTop:12}}>
      <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:12}}>
        <span style={{fontSize:16}}>{icon}</span>
        <span style={{
          color:C.purpleL,fontSize:11,fontWeight:700,
          textTransform:"uppercase",letterSpacing:1.5,fontFamily:S.fontUI
        }}>{label}</span>
      </div>
      {quote && (
        <>
          <p style={{
            color:C.goldL,fontSize:20,fontStyle:"italic",
            fontFamily:S.fontFamily,lineHeight:1.5,margin:"0 0 12px",textAlign:"center",textWrap:"balance"
          }}>"{quote}"</p>
          <hr style={{border:"none",borderTop:`1px solid ${C.border}`,margin:"0 0 12px"}}/>
        </>
      )}
      <div style={{color:C.goldL,fontSize:20,fontFamily:S.fontFamily,lineHeight:1.7}}>
        {expanded && renderText(cont)}
      </div>
      {cont && !expanded && (
        <Btn onClick={()=>setExpanded(true)} style={{width:"100%",marginTop:8,padding:"12px",borderRadius:12,background:C.cardDark,border:"1px solid "+C.purpleL+"55",color:C.purpleL,fontSize:14,fontWeight:700,fontFamily:S.fontUI}}>Leer más ▾</Btn>
      )}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginTop:16}}>
        <div style={{display:"flex",gap:14}}>
          <span onClick={()=>setLiked(!liked)} style={{fontSize:22,cursor:"pointer"}}>{liked?"❤️":"🤍"}</span>
          <span onClick={()=>shareQuote(quote, bg)} style={{fontSize:22,cursor:"pointer"}}>📤</span>
        </div>
        <Btn onClick={onClose} style={{
          background:C.cardDark,border:`1px solid ${C.border}`,
          borderRadius:20,padding:"8px 18px",color:C.text,
          fontSize:13,fontFamily:S.fontUI
        }}>✕ Cerrar</Btn>
      </div>
    </Card>
  );
}

